import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/creators.css';

const CreatorsPage = () => {
  const [creators, setCreators] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCreators();
  }, []);

  const fetchCreators = async () => {
    try {
      const response = await axios.get('http://localhost:3000/api/creators');
      setCreators(response.data);
    } catch (error) {
      console.error('Error fetching creators:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading creators...</div>;
  }

  const creatorData = [
    {
      id: 1,
      name: "Shinichirō Watanabe",
      role: "Director & Story Creator",
      description: "The visionary director behind Cowboy Bebop, Watanabe fused genres—film noir, western, and sci-fi—with a rhythm that matched the jazz-inspired score. His cinematic approach and episodic storytelling helped redefine anime in the late '90s.",
      image: "sinichiro.jpg"
    },
    {
      id: 2,
      name: "Yoko Kanno",
      role: "Composer & Music Director",
      description: "A musical genius known for her eclectic compositions, Kanno created the unforgettable sound of the series. From explosive jazz pieces like 'Tank!' to soulful ballads such as 'The Real Folk Blues', her work became inseparable from the show's identity.",
      image: ""
    },
    {
      id: 3,
      name: "Sunrise Studio",
      role: "Animation Studio",
      description: "The powerhouse behind numerous classics, Sunrise brought Cowboy Bebop to life with fluid animation, striking designs, and a visual style that captured both the grit of the underworld and the beauty of space.",
      image: ""
    }
  ];

  return (
    <main className="creators-page">
      {creatorData.map(creator => (
        <section key={creator.id} className="creator-card">
          {creator.image && (
            <img 
              src={`/images/${creator.image}`} 
              alt={creator.name} 
              className="creator-photo" 
            />
          )}
          <div className="creator-info">
            <h2>{creator.name}</h2>
            <p>
              <strong>{creator.role}</strong><br />
              {creator.description}
            </p>
          </div>
        </section>
      ))}
    </main>
  );
};

export default CreatorsPage;
